INSERT INTO task_execution (
    task_id, attempt_no, worker_id, status, heartbeat_at, started_at
) VALUES (
    #{taskId}, #{attemptNo}, #{workerId}, 'RUNNING',
    CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)
)

mapper.select:
SELECT 
FROM task_execution
WHERE task_id = #{taskId}
  AND attempt_no = #{attemptNo}
LIMIT 1

