UPDATE task_execution
SET status = 'FAILED',
    finished_at = CURRENT_TIMESTAMP(3),
    error_message = #{errorMessage}
WHERE id = #{id}
  AND status = 'RUNNING'
  AND (
      heartbeat_at IS NULL
      OR heartbeat_at < TIMESTAMPADD(SECOND, -#{timeoutSeconds}, CURRENT_TIMESTAMP(3))
  )
